local manager = require "manager.ActorManager"

GameStore = {}

local function getGoodsPrice(goods, player)
    local vip = player:getMaxVip()
    if vip == 0 then
        return goods.Price
    end
    if vip == 1 then
        return goods.PriceA
    end
    if vip == 2 then
        return goods.PriceB
    end
    if vip == 3 then
        return goods.PriceC
    end
    return goods.Price
end

local function getPlayerMoney(player, type)
    if type == Define.Money.DIAMOND then
        return player:getDiamond()
    end
    if type == Define.Money.GOLD then
        return 0
    end
    if type == Define.Money.VIRUSCRYSTAL then
        return player:getInventory():getItemNum(ItemID.VIRUSCRYSTAL)
    end
    if type == Define.Money.LIFECRYSTAL then
        return player:getInventory():getItemNum(ItemID.LIFECRYSTAL)
    end
    return 0
end

local function isCanAddRewards(player, rewards)
    local inv = player:getInventory()
    local records = {}
    local isFull = false
    for _, reward in pairs(rewards) do
        if reward.RewardType == Define.RewardType.Item then
            if inv:isCanAddItem(reward.RewardId, 0, reward.Count) then
                player:addItem(reward.RewardId, reward.Count, 0)
                table.insert(records, reward)
            else
                isFull = true
            end
        end
    end
    for _, record in pairs(records) do
        player:removeItem(record.RewardId, record.Count, 0)
    end
    return isFull
end

local function getRandomBoxRewards(supply)
    local rewards = {}
    local goodsList = GoodsPoolManager:randomGoods(supply.RandomPoolId, supply.RandomPoolParams)
    for _, goods in pairs(goodsList) do
        local config = StoreGoodsConfig:getGoodsById(goods.goodsId)
        if config ~= nil then
            table.insert(rewards, config.Reward)
        end
    end
    return rewards
end

function GameStore:consumeMoney(player, goodsId, type, price, param)
    if price == 0 then
        return true
    end
    if type == Define.Money.DIAMOND then
        player:consumeDiamonds(goodsId, price, param .. "#" .. goodsId)
        return false
    end
    if type == Define.Money.GOLD then
        return false
    end
    if type == Define.Money.VIRUSCRYSTAL then
        player:removeItem(ItemID.VIRUSCRYSTAL, price)
        return true
    end
    if type == Define.Money.LIFECRYSTAL then
        player:removeItem(ItemID.LIFECRYSTAL, price)
        return true
    end
    return false
end

function GameStore:onPlayerShopping(player, goodsId)
    local goods = StoreGoodsConfig:getGoodsById(goodsId)
    if not goods then
        return
    end
    if goods.Reward.RewardType == Define.RewardType.Item then
        local inv = player:getInventory()
        if not inv:isCanAddItem(goods.ItemId, 0, goods.Count) then
            HostApi.sendCommonTip(player.rakssid, "bag_full")
            return
        end
    end
    player:syncVipInfo()
    if goods.MoneyType == Define.Money.VIRUSCRYSTAL or goods.MoneyType == Define.Money.LIFECRYSTAL then
        local npc = manager:getActorById(player.storeEntityId)
        if not npc then
            return
        end
        if npc:getGoodsCount(goodsId) <= 0 then
            HostApi.sendCommonTip(player.rakssid, "the.goods.are.sold.out")
            return
        end
    end

    local money = getPlayerMoney(player, goods.MoneyType)
    local price = getGoodsPrice(goods, player)
    if money < price then
        if goods.MoneyType == Define.Money.VIRUSCRYSTAL then
            HostApi.sendCommonTip(player.rakssid, "virus_enough1")
        end

        if goods.MoneyType == Define.Money.LIFECRYSTAL then
            HostApi.sendCommonTip(player.rakssid, "virus_enough2")
        end

        return
    end
    local result = GameStore:consumeMoney(player, goods.GoodsId, goods.MoneyType, price, Define.BuyGoods)
    if result then
        GameStore:onPlayerBuyGoodsSuccess(player, goodsId)
    end
end

function GameStore:onPlayerBuyGoodsSuccess(player, goodsId)

    local goods = StoreGoodsConfig:getGoodsById(goodsId)
    if not goods then
        return
    end
    local rewardId = GameReward:onPlayerGetReward(player, goods.Reward)
    if rewardId then
        HostApi.notifyGetGoods(player.rakssid, goods.Reward.Image, goods.Reward.Count)
    end
    if goods.MoneyType == Define.Money.VIRUSCRYSTAL or goods.MoneyType == Define.Money.LIFECRYSTAL then
        local npc = manager:getActorById(player.storeEntityId)
        if not npc then
            return
        end
        if npc.__cname == "TravellerActor" then
            npc:onPlayerBuyGoods(goodsId, 1)
        end
    end
end

function GameStore:onPlayerBuySupplyFailed(player, supplyId)
    local supply = SupplyBoxConfig:getSupplyById(supplyId)
    if not supply then
        return
    end
    if supply.Type == Define.SupplyBox.TiroBox then
        player.tiro_box = false
    end
    if supply.Type == Define.SupplyBox.RandomBox then
        player.randomBoxRewards = nil
    end
end

function GameStore:onPlayerBuySupplyBox(player, supplyId)
    local supply = SupplyBoxConfig:getSupplyById(supplyId)
    if not supply then
        return
    end
    local rewards = supply.Rewards
    if supply.Type == Define.SupplyBox.RandomBox then
        if player.randomBoxRewards ~= nil then
            return
        end
        player.randomBoxRewards = getRandomBoxRewards(supply)
        rewards = player.randomBoxRewards
    end
    if  isCanAddRewards(player, rewards) then
        HostApi.sendCommonTip(player.rakssid, "bag_full")
        return
    end
    if supply.Type == Define.SupplyBox.TiroBox then
        if player.tiro_box then
            HostApi.sendCommonTip(player.rakssid, "new_gift_bags_can_only_be_bought_once")
            return
        end
        player.tiro_box = true
    end
    if supply.Type == Define.SupplyBox.DailyBox then
        if player.daily_box + supply.RefreshTime > os.time() then
            return
        end
    end
    if supply.Type == Define.SupplyBox.VipBox then
        local vip = player:getMaxVip()
        if player.vip_box >= vip then
            return
        end
    end
    local money = getPlayerMoney(player, supply.MoneyType)
    local price = getGoodsPrice(supply, player)
    if money < price then
        return
    end
    local result = GameStore:consumeMoney(player, supply.Id, supply.MoneyType, price, Define.BuySupplyBox)
    if result then
        GameStore:onPlayerBuySupplySuccess(player, supplyId)
    end
end

function GameStore:onPlayerBuySupplySuccess(player, supplyId)
    local supply = SupplyBoxConfig:getSupplyById(supplyId)
    if not supply then
        return
    end
    local rewards = {}
    if supply.Type == Define.SupplyBox.TiroBox then
        rewards = supply.Rewards
        player.tiro_box = true
    end
    if supply.Type == Define.SupplyBox.DailyBox then
        rewards = supply.Rewards
        player.daily_box = os.time()
    end
    if supply.Type == Define.SupplyBox.RandomBox then
        if player.randomBoxRewards == nil then
            player.randomBoxRewards = getRandomBoxRewards(supply)
        end
        rewards = player.randomBoxRewards
        player.randomBoxRewards = nil
    end
    if supply.Type == Define.SupplyBox.VipBox then
        rewards = supply.Rewards
        player.vip_box = player.vip_box + 1
    end
    HostApi.notifyGetGoods(player.rakssid, supply.Image, 1)
    for _, reward in pairs(rewards) do
        local rewardId = GameReward:onPlayerGetReward(player, reward)
        if rewardId then
            --HostApi.notifyGetGoods(player.rakssid, reward.Image, reward.Count)
        end
    end
    GameStore:syncSupplyData(player)
end

function GameStore:syncSupplyData(player)
    local data = {}
    local tiro_box = SupplyBoxConfig:getSupplyByType(Define.SupplyBox.TiroBox)
    local daily_box = SupplyBoxConfig:getSupplyByType(Define.SupplyBox.DailyBox)
    local random_box = SupplyBoxConfig:getSupplyByType(Define.SupplyBox.RandomBox)
    local vip_box = SupplyBoxConfig:getSupplyByType(Define.SupplyBox.VipBox)
    for _, box in pairs(tiro_box) do
        local item = { Id = box.Id, Time = -1 }
        if player.tiro_box then
            item.Status = Define.SupplyBoxStatus.UnBuy
        else
            item.Status = Define.SupplyBoxStatus.CanBuy
        end
        table.insert(data, item)
    end
    for _, box in pairs(daily_box) do
        local item = { Id = box.Id }
        if player.daily_box + box.RefreshTime <= os.time() then
            item.Status = Define.SupplyBoxStatus.CanReceive
            item.Time = 0
        else
            item.Status = Define.SupplyBoxStatus.UnReceive
            item.Time = (player.daily_box + box.RefreshTime) - os.time()
        end
        table.insert(data, item)
    end
    for _, box in pairs(random_box) do
        local item = {
            Id = box.Id,
            Status = Define.SupplyBoxStatus.CanBuy,
            Time = -1
        }
        table.insert(data, item)
    end
    local vip, time = player:getMaxVip()
    local curtime = math.max(0, time - os.time())
    if curtime < 0 then
        player.vip_data.level = 0
    end
    for _, box in pairs(vip_box) do
        local item = { Id = box.Id, Time = -1 }
        if player.vip_box < vip and curtime > 0 then
            item.Status = Define.SupplyBoxStatus.CanReceive
        else
            item.Status = Define.SupplyBoxStatus.UnReceive
        end
        table.insert(data, item)
    end
    GamePacketSender:sendWalkingDeadSupplyData(player.rakssid, json.encode(data))
end

return GameStore
